#### Example

```javascript
const fs = TTMinis.game.getFileSystemManager();
// Check if a file/directory exists
fs.access({
  path: `${TTMinis.game.env.USER_DATA_PATH}/hello.txt`,
  success(res) {
    // File exists
    console.log(res)
  },
  fail(res) {
